export default function MuscleModel({ muscleRanks = {}, recoveryData = {}, showRecovery = false, onMuscleRank }) {
  const [view, setView] = useState("front");
  const [clickedMuscle, setClickedMuscle] = useState(null);
  const navigate = useNavigate();

  const getMuscleColor = (groupId) => {
    const muscleName = GROUP_TO_MUSCLE[groupId];
    if (!muscleName) return null;
    if (showRecovery) {
      // recoveryData is keyed by lowercase group name (from workout log muscle_group field)
      const key = muscleName.toLowerCase();
      const state = recoveryData[key] || "fresh";
      const idx = RECOVERY_ORDER.indexOf(state);
      return idx >= 0 ? RECOVERY_COLORS[idx] : RECOVERY_COLORS[0];
    }
    const idx = RANK_ORDER.indexOf(muscleRanks[muscleName]);
    return idx >= 0 ? RANK_COLORS[idx] : "#B8B8B8";
  };

  const handleMuscleClick = (groupId) => {
    const muscleName = GROUP_TO_MUSCLE[groupId];
    if (muscleName) setClickedMuscle(muscleName);
  };

  const renderGroups = (groups) =>
    Object.entries(groups).map(([id, paths]) => {
      const color = getMuscleColor(id);
      const isClickable = !!(GROUP_TO_MUSCLE[id]);
      const fill = color || "#B8B8B8";
      return (
        <g
          key={id}
          fill={fill}
          fillOpacity={isClickable ? 0.9 : 0.7}
          stroke="rgba(0,0,0,0.25)"
          strokeWidth="0.5"
          onClick={() => handleMuscleClick(id)}
          style={{ cursor: isClickable ? "pointer" : "default" }}
        >
          {paths.map((d, i) => <path key={i} d={d} />)}
        </g>
      );
    });

  // Front: 663x1509, Back: 656x1503
  const containerW = 220;
  const containerH = view === "front"
    ? Math.round(containerW * 1509 / 663)
    : Math.round(containerW * 1500 / 656);

  return (
    <div className="relative">
      {/* View toggle */}
      <div className="flex justify-center gap-2 mb-3">
        {["front", "back"].map(v => (
          <button key={v} onClick={() => setView(v)}
            className={`px-4 py-1 rounded-full text-xs font-semibold capitalize transition-all ${
              view === v ? "bg-primary text-white" : "bg-secondary text-muted-foreground"
            }`}>
            {v}
          </button>
        ))}
      </div>

      {/* Body model + SVG overlay */}
      <div className="flex justify-center">
        <AnimatePresence mode="wait">
          <motion.div
            key={view}
            initial={{ opacity: 0, x: view === "front" ? -20 : 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: view === "front" ? 20 : -20 }}
            transition={{ duration: 0.15 }}
            onTouchStart={(e) => { e.stopPropagation(); e.currentTarget._sx = e.touches[0].clientX; }}
            onTouchEnd={(e) => {
              e.stopPropagation();
              const diff = e.changedTouches[0].clientX - (e.currentTarget._sx || 0);
              if (Math.abs(diff) > 40) setView(diff > 0 ? "front" : "back");
            }}
            style={{ position: "relative", width: `${containerW}px`, height: `${containerH}px` }}
          >
            {view === "front" ? (
              <svg
                viewBox="0 0 663 1509"
                preserveAspectRatio="xMidYMid meet"
                style={{ position: "absolute", inset: 0, width: "100%", height: "100%" }}
              >
                {/* Body silhouette */}
                <path d={FRONT_BODY_PATH} fill="#D0D0D0" stroke="rgba(0,0,0,0.3)" strokeWidth="1" />
                {/* Hair */}
                <path d={FRONT_HAIR_PATH} fill="#A8A8A8" stroke="rgba(0,0,0,0.3)" strokeWidth="0.5" />
                {/* Face/neck skin */}
                {FRONT_FACE_PATHS.map((d, i) => (
                  <path key={i} d={d} fill="#D0D0D0" stroke="rgba(0,0,0,0.2)" strokeWidth="0.5" />
                ))}
                {/* Muscle map */}
                {renderGroups(FRONT_GROUPS)}
              </svg>
            ) : (
              <svg
                viewBox="0 0 656 1500"
                preserveAspectRatio="xMidYMid meet"
                style={{ position: "absolute", inset: 0, width: "100%", height: "100%" }}
              >
                {/* Body silhouette */}
                <path
                  d={BACK_BODY_PATH}
                  fill="#D0D0D0"
                  stroke="rgba(0,0,0,0.3)"
                  strokeWidth="1"
                />
                {/* Hair */}
                <path d={BACK_HAIR_PATH} fill="#A8A8A8" stroke="rgba(0,0,0,0.3)" strokeWidth="0.5" />
                {renderGroups(BACK_GROUPS)}
              </svg>
            )}
          </motion.div>
        </AnimatePresence>
      </div>

      <p className="text-center text-[10px] text-muted-foreground mt-1">Tap muscle to find exercises · Swipe to flip</p>

      {/* Muscle click popup */}
      <AnimatePresence>
        {clickedMuscle && (
          <>
            <div className="fixed inset-0 z-50" onClick={() => setClickedMuscle(null)} />
            <motion.div
              initial={{ opacity: 0, scale: 0.9, y: 8 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: 8 }}
              transition={{ duration: 0.15 }}
              className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-50 bg-card border border-border rounded-2xl p-5 shadow-2xl w-64 text-center"
            >
              <p className="text-xs text-muted-foreground mb-1">Muscle selected</p>
              <p className="text-lg font-bold mb-4">{MUSCLE_LABELS[clickedMuscle] || clickedMuscle}</p>
              <button
                onClick={() => {
                  const encoded = encodeURIComponent(clickedMuscle);
                  navigate(createPageUrl(`Lifts?tab=exercises&submuscle=${encoded}`));
                  setClickedMuscle(null);
                }}
                className="w-full bg-primary text-white rounded-xl py-2.5 text-sm font-semibold"
              >
                See Exercises
              </button>
              <button
                onClick={() => {
                  onMuscleRank?.(clickedMuscle);
                  setClickedMuscle(null);
                }}
                className="w-full mt-2 bg-secondary text-foreground rounded-xl py-2.5 text-sm font-semibold"
              >
                See Rank
              </button>
              <button onClick={() => setClickedMuscle(null)}
                className="w-full mt-2 text-xs text-muted-foreground py-1.5">Cancel</button>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}